// Process Whisper response and prepare for analysis
const whisperResponse = $input.first().json;
const inputData = $('Process Trigger').first().json;

// Structure the transcript with segments
const transcript = {
  call_id: inputData.call_id,
  full_text: whisperResponse.text,
  language: whisperResponse.language,
  duration: whisperResponse.duration,
  segments: (whisperResponse.segments || []).map(seg => ({
    id: seg.id,
    start: seg.start,
    end: seg.end,
    text: seg.text.trim(),
    confidence: seg.confidence || null
  })),
  word_count: whisperResponse.text.split(/\s+/).length,
  transcribed_at: new Date().toISOString()
};

return { json: transcript };

