// Parse GPT-4 analysis response
const gptResponse = $input.first().json;
const transcript = $('Process Transcript').first().json;
const inputData = $('Process Trigger').first().json;

let analysis;
try {
  const content = gptResponse.choices[0].message.content;
  analysis = JSON.parse(content);
} catch (e) {
  analysis = {
    summary: 'Analysis parsing failed',
    customer_intent: 'Unknown',
    resolution_status: 'unknown',
    topics: [],
    sentiment: { label: 'neutral', confidence: 0 },
    action_items: [],
    entities: []
  };
}

// Combine all data
const processedCall = {
  call_id: transcript.call_id,

  // Transcript data
  transcript: {
    full_text: transcript.full_text,
    segments: transcript.segments,
    word_count: transcript.word_count,
    duration: transcript.duration,
    language: transcript.language
  },

  // Analysis data
  analysis: {
    summary: analysis.summary,
    customer_intent: analysis.customer_intent,
    resolution_status: analysis.resolution_status,
    topics: Array.isArray(analysis.topics) ? analysis.topics : [],
    sentiment: analysis.sentiment,
    action_items: Array.isArray(analysis.action_items) ? analysis.action_items : [],
    entities: Array.isArray(analysis.entities) ? analysis.entities : []
  },

  // Original metadata
  metadata: inputData.metadata || {},

  // Processing info
  processing: {
    transcribed_at: transcript.transcribed_at,
    analyzed_at: new Date().toISOString(),
    model_used: 'gpt-4-turbo',
    whisper_model: 'whisper-1',
    workflow_version: '1.0.0'
  }
};

return { json: processedCall };

// Add embedding to processed call data
const processedCall = $('Combine Results').first().json;
const embeddingResponse = $input.first().json;

processedCall.embedding = {
  vector: embeddingResponse.data[0].embedding,
  model: 'text-embedding-ada-002',
  dimensions: embeddingResponse.data[0].embedding.length,
  generated_at: new Date().toISOString()
};

return { json: processedCall };
